    } else if (code === 92) { //       result += backslash + backslash;
    } else if (code === 8) { //  
      result += backslash + "b";
    } else if (code === 9) { // 	
      result += backslash + "t";
    } else if (code === 10) { // 

      result += backslash + "n";
    } else if (code === 12) { //  
      result += backslash + "f";
    } else if (code === 13) { // 
      result += backslash + "r";
    } else if (code === 0x2028 || code === 0x2029) {
      result += backslash + "u" + code.toString(16);
    } else if (code < 32) {
      var hex = code.toString(16);
